import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"废土守望者-藏身处","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/废土守望者/废土守望者-藏身处.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/废土守望者/废土守望者-藏身处.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/废土守望者/废土守望者-藏身处.md"};function o(_,p,d,l,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"废土守望者-藏身处",tabindex:"-1"},[t("废土守望者-藏身处 "),r("a",{class:"header-anchor",href:"#废土守望者-藏身处","aria-label":'Permalink to "废土守望者-藏身处"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),n('<h1 id="藏身处" tabindex="-1">藏身处 <a class="header-anchor" href="#藏身处" aria-label="Permalink to &quot;藏身处&quot;">​</a></h1><p>废土守望者-藏身处</p><p>与一般的轮回者不同，废土守望者将解锁【藏身处】作为其在主神空间中的活动据点。废土守望者在解锁【藏身处】时，一并获得其中所有设施栏位，它们初始均为0级。设施等级若无特殊说明，则一/二/三级设施对应D/C/B级或是1/2/3点对应的数字。<br> 设施只能通过消耗废土守望者所挖掘出的资源进行升级，如无特殊说明，【藏身处】的设施升级会在每项设施中标注出，每次升级只需上交记载的资源便可提升一级。建造低级设施/提升初级设施等级会为废土守望者提供2点自由属性点，建造高级设施会为废土守望者提供记载的收益。<br> 少量设施会被标记为高级设施，具有额外建造需求。</p><p>终于，你找到了一处已经废弃多年的地下设施，这里看起来曾经是实验室，只不过仪器早就已经被搬走，只剩下还算隐蔽的入口。<br> 将这里重新修整成你的基地或许是一条艰难而漫长的路，但人总需要一个藏身之所，并为了把它建设的更好而努力，这是人类的原动力。</p><p>管道系统<br> 类型：初级设施<br> 管道系统初始为0级，上限为3级。<br> 每次提升管道系统所需等价于2000分的金属和等价于1000分的零件。</p><p>1级管道系统<br> 这里确实曾存在一定程度的管道系统，为实验室的污水排放起到作用。但如今，这里早已废弃许久，只剩下几根早已停止使用而堵塞的管道。经过重新修整，它们已勉强开始工作。</p><p>1级管道系统会为你提供如下效果：<br> 当你进行强韧豁免时，你额外获得等同于管道系统等级*2点强韧豁免检定的器械加值。当你当你忍耐不良点数时，若忍耐的不良点数为剧痛/眩晕/恐惧中的一种，则可以额外忍耐等同于管道系统等级*1点此种不良点数。</p><p>2级管道系统<br> 经过你的进一步重建，并多焊接了几条出水管，现在，管道系统不再像从前那般只排出一点点污水就会堵塞了。埋进地面中的管道网总算初具雏形。</p><p>2级管道系统会为你提供如下效果：<br> 每场景一次，当你进行强韧豁免时，你可以至多重投等同于管道系统等级-1次检定，你必须在那次检定中用掉这一效果带来的全部重投次数，也可以选择接受某一次的结果而放弃剩余重投次数，你必须接受重投后的结果。</p><p>3级管道系统<br> 需求：电力系统2级 通风扇2级<br> 最终，你的藏身处的地下已铺设出了足以支撑大量用水的排污管道，它们被精心保养，时常检查，以免出现任何堵塞等意外状况，还有备用管道，通过阀门控制，以应对意外状况。</p><p>3级管道系统会为你提供如下效果：<br> ·若你已在强韧豁免上拥有加骰等级，则1级管道系统提供的强韧豁免相关效果翻倍。<br> ·若你已拥有增加强韧豁免的【适应】，则2级管道系统提供的重投次数不再-1。</p><p>净水器<br> 类型：初级设施<br> 净水器初始为0级，上限为3级。<br> 每次提升净水器所需等价于1500分的金属、等价于1000分的辐射罐和等价于500分的生物质能。</p><p>1级净水器<br> 在废土生存，必须要喝干净的水才能保持身体健康。所幸，在废弃的垃圾堆中，你收拾出了一套还能使用的低效净水器。</p><p>1级净水器会为你提供如下效果：<br> 现在，你的疲乏周期会延长等同于净水器等级*1倍。每场景一次，当你承受恶心点数时，你可以至多无视等同于净水器等级*2点恶心点数。</p><p>2级净水器<br> 你为净水器更换了新的滤网，并接上了一个额外的过滤器插槽，增加了净水效率。这让净水器能够在同等时间内净化的水份更多。</p><p>2级净水器开启【1】个过滤器槽位。<br> 2级净水器会为你提供如下效果：<br> 每场景一次，当你承受有关生理方面的异常点数（如：肢体障碍、恶心、疲乏等）时，你将立即获得至多等同于净水器等级-1点异常点数治疗（医疗点=（净水器等级-1）*12），这些异常点数治疗将持续存在一轮。</p><p>若你的净水器上还安装了过滤器，则在每场影片结束时，过滤器将自动完全失去功效。你将因此而获得等价于350分的纯净水，可以选择售卖给主神获取等量分数，或等价兑换成一种任意【废土守望者】资源。</p><p>每个过滤器可以在主神处以250分的价格进行购买。</p><p>3级净水器<br> 终于，你将这个原本破烂的净水器修整完毕，优质的，具有延展性的软管，全力运转的净水马达，虽然一刻不停的嗡嗡作响，但总算是能够得到稳定干净的水源了。</p><p>3级净水器再解锁【3】个过滤器槽位。<br> 3级净水器会为你提供如下效果：<br> ·若你已消耗过5个及以上的过滤器，则解锁净水器酿制【真快活】的能力。<br> ·净水器2级提供的异常点数治疗将不再被每场景一次所限制。</p><p>酿制【真快活】和集水只能选择一种，在每场影片结束时选择获得纯净水或【真快活】。每瓶【真快活】需要2个过滤器同时工作才能酿制，每瓶等价于750分。可以选择售卖给主神获取等量分数，或等价兑换成一种任意【废土守望者】资源。也可以在影片内使用，饮用真快活与饮用液体所需动作相同，一瓶仅能饮用一次，饮用后，将立即获得持续一个场景的3点寒冷伤害吸收、免疫冻结异常点数的减值与严重效果、并再获得6点攻击检定上的士气加值。此外，如使用者的生命最好状态中不保有完好，则自动停止伤势恶化。</p><p>电力系统<br> 类型：初级设施<br> 电力系统初始为0级，上限为3级。<br> 每次提升电力系统所需等价于1500分的金属和等价于1500分的零件。</p><p>1级电力系统<br> 没有电力，一切都无法正常运行，因此，你想尽办法搞到了一台不怎么样的老式柴油发电机，虽然发电效率低下，噪声巨大，但好在总算是让你的藏身处亮起来了。</p><p>1级电力系统会为你提供如下效果：<br> 你将获得黑暗视觉，现在你能够搭建供电设施，这需要在非战斗场景下花费4个小时与价值50分的零件，供电设施可为合计功率不超过10KW的电器提供能源。</p><p>2级电力系统<br> 在经过维修后，电力系统有所改善，现在使用了更大功率的转化装置，但问题也随之而来，简陋的通风设施已经无法使发电机进行进一步的改进。</p><p>2级电力系统会为你提供如下效果：<br> 你获得免疫目盲能力，其免疫等级等同于电力系统等级+1（2级等同于B级，3级等同于A级）。</p><p>3级电力系统<br> 需求：通风扇3级<br> 在更新了通风设施后，电力系统也迎来了最后一次升级，原本错综复杂的线路网被重整，并埋入墙壁中以保安全。有了电力的辅助，建造其他设施也将获得更多助力。</p><p>3级电力系统会为你提供如下效果：<br> 每当你建造或升级设施时，若为低级设施，则最多可以免除设施所需资源中的共计不超过500分的等价资源。</p><p>通风扇<br> 类型：初级设施<br> 通风扇初始为0级，上限为3级。<br> 每次提升通风扇所需等价于1000分的金属、等价于1000的零件、和等价于1000分的生物质能。</p><p>1级通风扇<br> 几片草率焊接的叶片，一个联通地面的洞，就已经是现在都全部，排风效率很差，室内的空气也浑浊不堪，但总算是有一些空气流通。</p><p>1级通风扇会为你提供如下效果：<br> 每场景一次，当你对毒素点数进行强韧豁免时，你额外获得等同于通风扇等级*2点检定上的附加成功。</p><p>2级通风扇<br> 安装了额外的抽气装置，将室内的污浊空气抽出送向地面，确实一定程度上改善了当前环境。</p><p>2级通风扇会为你提供如下效果：<br> 你免疫C级别的毒素来源的负面效果。当你进行强韧豁免时，若你正对那次强韧豁免检定进行重投，则那次检定将额外提升等同于通风扇等级-1级加骰，至多为8加骰。</p><p>3级通风扇<br> 增加了空气过滤罐的安装位置，再次修整了整个通风系统，现在，不仅可以将浑浊的空气排除，还可以对空气进行进一步过滤和净化。</p><p>3级通风扇开启【1】个空气过滤罐槽位。<br> 3级通风扇会为你提供如下效果：<br> 你免疫B级别的毒素来源的负面效果。<br> 现在，当你受到对于生理属性造成的属性伤害时，你立即吸收其中对你造成的2点属性伤害。</p><p>每个空气过滤罐可以在主神处以500分的价格进行购买。每场影片结束时，空气过滤罐将提供1自由属性点，这些自由属性点只能提升生理属性等级。在经过两场影片后，空气过滤罐将耗尽其中的滤芯活性，失去作用。</p><p>休息室<br> 类型：初级设施<br> 休息室初始为0级，上限为3级。<br> 每次提升休息室所需等价于1000分的金属、等价于1000的零件、和等价于1000分的生物质能。</p><p>1级休息室<br> 一个舒适的居住环境能让你的精力充沛，而显然，现在的条件并不足以让你有多放松，但也没那么糟糕，至少有地方能够休息，一张床垫子就够了。</p><p>1级休息室会为你提供如下效果：<br> 现在，你获得自适应短休息的能力，每天一次，当你进行短休息时，你将额外恢复1点只能用于攻击检定上的意志力，不能超过意志力池上限。</p><p>2级休息室<br> 原本放在潮湿地面上的床垫被改换为了柔软的吊床，崭新的布料让它更加舒适，还有一台不知从哪淘来的破电视可以用于打发时间。</p><p>2级休息室会为你提供如下效果：<br> 现在，你获得自适应长休息的能力，你的长休息时间将减少一半。</p><p>3级休息室<br> 最后，吊床也被摘下，而是重新用铁条焊了一架结实耐用的铁架床，你所能找到的最好的布料铺设在上面，在床边摆着的便是你从各个地方搞来的游戏卡带，以及一台游戏机。在游戏机的旁边，还有当做屏幕使用的电视。</p><p>3级休息室会为你提供如下效果：<br> 你的每次长休结束后，接下来的第一个场景内进行的所有检定额外获得等同于休息室等级-1点检定上的士气加值。</p><p>医疗中心<br> 类型：初级设施<br> 需求：1级净水器 1级休息室<br> 医疗中心初始为0级，上限为3级。<br> 每次提升医疗中心所需等价于2000分的辐射罐和等价于1000分的生物质能。</p><p>1级医疗中心<br> 在废土生存，受伤是在所难免的，如果处理不好，伤势就会恶化，还会造成更加严重的后果。好在实验室中还保留了一些没有带走的医疗器械和药物，你用它们搭建了一处简陋的医疗中心。</p><p>1级医疗中心开启【1】个制药栏。<br> 1级医疗中心会为你提供如下效果：<br> 选择一点你拥有的快速治疗，该点快速治疗额外获得等同于医疗中心等级*8点医疗点。服用你制造的药物的单位将清除自身当前具有的D级别疾病来源的负面效果，这一效果会随着医疗中心等级提升而提升至清除C/B级疾病来源的负面效果。</p><p>制药栏的使用方式如下：<br> 使用智力-器用-制药进行制药检定，制药检定的检定流程与造物检定完全一致，制药栏需要你在医疗中心内才可进行制药，除你之外，他人也可以在你的同意下使用制药栏进行药物制造。能够被制造的药物等级不能超过医疗中心等级（1级等同于基础D级，2级等同于基础C级，3级等同于基础B级），制造的药物需要为具有消耗次数的非永久性生效的药物，不能制造非通用药物，不能制造非废土守望者所属的资源下属药物（例：玩家逆位【星星】可以通过制药栏制造快速伤药，但无法制造空无士兵下属药物柯罗诺斯）。</p><p>2级医疗中心<br> 你花费了大量时间和人力物力，终于在医疗中心内部拓展出一间无菌室，虽然自己给自己做手术是一件几乎不可能的事，但你暂时可以用其他方式替代。</p><p>2级医疗中心会为你提供如下效果：<br> 当你的生命中最好状态不保有完好时，你将不会因失去所有完好而晕倒。当你进行包扎伤口或切开血管排毒时，你将额外再获得1点仅能在当轮使用的快速医疗（医疗点12）。</p><p>3级医疗中心<br> 现在，你已经能制造更多药物，并用全套设备排查自己的身体的问题，及时找出伤势源头与疾病隐患。</p><p>3级医疗中心额外再开启【1】个制药栏，这只会令他人能够与你同时使用制药栏进行制造药品。<br> 3级医疗中心会为你提供如下效果：<br> 现在，你可以使用制药专业替代造物专业进行检定，也可以造物专业替换制药专业进行检定。现在，你每使用制药栏制造一份D级及以上的药物，就可以指定一点你拥有的快速医疗，令其提升8点医疗点（他人使用你的制药栏不会获得这一效果）。</p><p>入口<br> 类型：初级设施<br> 入口初始为0级，上限为3级。<br> 每次提升入口所需等价于3000分的金属。</p><p>1级入口<br> 实际上，现在的入口毫无安全性可言，它只是暂时隐藏的很好，你当时也只是误打误撞发现了这片无主之地，但你不确定以后还会不会有细心者发现你的秘密基地，因此，至少要安装一扇大门才行。</p><p>1级入口会为你提供如下效果：<br> 你获得等同于入口等级*5点器械防御，你获得基于器械防御的【防弹】能力。</p><p>2级入口<br> 在加装了铁门后，你还准备了一些安保措施，用于应对潜在的闯入者，但限于你的手头没有太好的材料，铁门本身也仍不算牢靠。</p><p>2级入口会为你提供如下效果：<br> 你获得基于器械防御的【劣化1】，但这一【劣化】效果每场景只能触发一次。</p><p>3级入口<br> 现在，厚重的金属大门成了最好的庇护方式，这些材料都是你从附近的一处银行废墟的保险柜门上割下来的。全套的应对入侵装置让你对挡住一切入侵者有了充足的信心。</p><p>3级入口会为你提供如下效果：<br> 你获得基于器械防御的【劣化2】，这一劣化效果触发时，若攻击者的攻击掷骰出目高于DP的1/3，则这一劣化效果在场景内失效。</p><p>提炼机<br> 类型：高级设施<br> 提炼机初始为0级，上限为1级。<br> 每次提升提炼机所需等价于1250分的金属、等价于1250分的零件、等价于1250分的生物质能和等价于1250分的辐射罐<br> 需求：电力系统2级 通风扇2级</p><p>1级提炼机<br> 你已经受够了收集装置的低效，并开始思考如何进一步将收集到的各类材料变为更多可利用的资源，因此，一份提炼机的原型图就从迈克斯达尔博士的手上来到了你的工作台上。</p><p>1级提炼机将不会为你提供自由属性点，而是为你提供：<br> ·材料提炼：材料提炼初始具有【1】个提炼槽位，提炼材料需要一场影片时间，在影片结束后回到藏身处才能收获材料。在藏身处初级设施等级共计达到7/14/21级时，这个槽位将变为2/3/4个。<br> 提炼流程：在藏身处中可以选择某种你拥有的足量的材料，将其投入提炼机中，一个提炼槽只能同时提炼一种材料。材料最低价值为500分，最高为3000分，且必须为250的倍数，下一场影片结束时，将提炼出总价值为（原价值+原价值/2）的那种材料（例：玩家逆位【太阳】选择投入价值为500分的生物质能，在经过提炼后，提炼出了总价值为500+500/500*250=750分的生物质能，若总投入数不是500的倍数，则忽略不足的部分。</p><p>材料转化<br> 原本的材料转化方式将被提炼机的转化方式取代，材料转化初始具有【1】个转化槽位，转化材料需要一场影片时间，在影片结束后回到藏身处才能收获材料。<br> 转化材料将变为1:1转化率，不再具有亏损，转化槽位个数根据你解锁的除提炼机外的藏身处高级设施个数而增加，这个槽位将变为2/3/4个。转化材料也具有上限，每个槽位能转化的材料上限不超过等价于1500分的某种材料*解锁的高级设施数量（例：玩家逆位【恋人】仅解锁了【提炼机】，则其当前每个槽位的转化上限为1500分的某材料；玩家逆位【女祭司】解锁了【提炼机】和【藏书室】，则其每个槽位的转化上限提升为1500*2=3000分某材料）。</p><p>健身房<br> 类型：高级设施<br> 健身房初始为0级，上限为1级。<br> 每次提升健身房所需等价于1250分的金属、等价于1250分的零件、等价于1250分的生物质能和等价于1250分的辐射罐<br> 需求：休息室2级 医疗中心2级</p><p>1级健身房<br> 在废土生存，强身健体似乎已经成了必修课，你总是要和各种变异怪物以及掠夺者打交道。因此，你通过收集和自制器材的方式拼凑出了一间健身房，能够在此锻炼你的肌肉。</p><p>1级健身房将不会为你提供自由属性点，而是为你提供：<br> ·基础训练<br> 除购买的那场影片结束，每场影片结束后，才能在健身房进行一次基础训练，下一场影片开始前，你购买的前5点生理类属性将可以支付等价的生物质能，并减少为每1点生理类属性支付250分。</p><p>·战斗训练<br> 立即解锁【战术假人】，你可以在健身房中与战术假人练习战斗，你可以自行设定战术假人的攻击检定数值、防御构成及数值、具有的特性等能力。<br> 除购买的那场影片结束，每场影片结束后仅一次，当你与战术假人训练后，你可以选择一项你具有的生理类技能下属专业，将其提升1级，并再选择一项你具有的攻击检定，使那项攻击检定获得1点永久的士气加值。</p><p>情报板<br> 类型：高级设施<br> 战术板初始为0级，上限为1级。<br> 每次提升情报板所需等价于1250分的金属、等价于1250分的零件、等价于1250分的生物质能和等价于1250分的辐射罐<br> 需求：净水器2级 入口2级</p><p>1级情报板<br> 这是一张上面挂满情报资料、照片与红蓝线的白板，写满了你对当前局势的分析与判断。有关于核灭世的错综复杂的真相逐渐展露在你的面前。</p><p>1级情报板将不会为你提供自由属性点，而是为你提供：<br> ·制造奇物<br> 情报板只有【1】个奇物制造栏位，只能制造废土生存手册中记录的奇物。制造的奇物等级上限在藏身处初级设施等级共计达到7/14/21级时，提升至C/B/A级。<br> 制造废土生存手册中记录的奇物不使用造物检定，也不进行任何检定，而是在除购买的那场影片结束的每场影片结束后选择一个可以制造的奇物，在X场影片后，这一奇物将被自动造出（X为无支线1/D2/C3/B4/A5），也可以选择投入额外的2500分或等价于2500分的任意材料进行催化，使所需影片数减少一场，最少为一场。</p><p>藏书室<br> 类型：高级设施<br> 藏书室初始为0级，上限为1级。<br> 每次提升藏书室所需等价于1250分的金属、等价于1250分的零件、等价于1250分的生物质能和等价于1250分的辐射罐<br> 需求：管道系统2级 电力系统2级</p><p>1级藏书室<br> 这是一间储存着你从废土上的各个角落搜罗来的书籍的特殊房间，在这个知识匮乏的时代，拥有这样一间藏书室能抵万金。</p><p>1级藏书室将不会为你提供自由属性点，而是为你提供：<br> ·自我学习<br> 现在，你获得一种特殊的专业购买方式，这一专业被称为【触类旁通】。触类旁通可以作为任何技能的下属专业参与检定，触类旁通的计算方式不同于普通的专业，它在计算时视为该技能下的任意专业，所有属于该技能的检定都可以将触类旁通作为所需的下属专业加入检定，但触类旁通等级和该专业的原等级合计仍不能超过技能等级（例：玩家力量在武技上购买了1级剑专业，他的武技技能有3级，则他至多只能在使用剑专业进行攻击检定时，将武技上的触类旁通专业等级中的2级加入检定之中）。每级触类旁通等级需花费等价于1500分的材料进行购买，购买的触类旁通等级总和不能超过藏身处初级设施等级合计/2（向较少的一方取整）。<br> 在解锁藏书室时，你立即获得3级触类旁通专业。</p><p>秘密通道<br> 类型：高级设施<br> 秘密通道初始为0级，上限为1级。<br> 每次提升秘密通道所需等价于6000分的金属、等价于6000分的零件、等价于6000分的生物质能和等价于6000分的辐射罐。<br> 需求：管道系统3级 净水器3级 电力系统3级 通风扇3级 休息室3级 医疗中心3级 入口3级 提炼机 健身房 情报板 藏书室<br> ·主持人有权禁止此设施能力。</p><p>1级秘密通道<br> 最终，你惊讶的发现在整个实验室的地下有一道不知通往何处的秘密通道，你心怀忐忑的走了进去，却没能鼓起勇气打开尽头的那扇门。</p><p>1级秘密通道将不会为你提供自由属性点，而是为你提供：<br> 1.你可以在主神空间中通过秘密通道回到任何一个你曾到达过，并标记过锚点的世界，这将花费你一个小时的准备时间，这是一个A级时空来源的旅行效果。<br> 2.你可以在影片中随时以一个小时的准备时间返回藏身处，不能在战斗场景中使用，在回到藏身处后，你可以如常使用任何藏身处内的设施，这不视为经历了一场影片，你必须在回到藏身处后的下一个场景开始时返回原影片。这是一个A级时空来源的旅行效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',77)])])}const m=b(s,[["render",o]]);export{f as __pageData,m as default};
